from car_class import Cardef class_header(text):    return f"___{text}___\n"def main():    my_car = Car("2026","Ford")    print(class_header("Accelerating..."))    for i in range (5):        my_car.accelerate()        print(f"Acceleration  {i+1}: Current speed is {my_car.get_speed()} mph")        print("\n" +class_header("Accelerating..."))    for i in range (5):        my_car.brake()        print(f"Brake  {i+1}: Current speed is {my_car.get_speed()} mph")if __name__ == "__main__":        main ()